SELECT object_name
FROM celestial_objects
WHERE object_id = '0';

SELECT COUNT(*) 
FROM observation_requests 
WHERE status = 'approved';

SELECT request_date
FROM observation_requests
WHERE status = 'approved' AND priority >= 2;

SELECT obs_id
FROM observations
ORDER BY obs_id;

SELECT COUNT(*) 
FROM observation_schedules 
WHERE scheduled_date = '2023-05-01';
